use core::fmt;
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BranchKind { Beq, Bne, Blt, Bge, Bltu, Bgeu }
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum LoadKind { Byte, Half, Word, ByteUnsigned, HalfUnsigned }
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum StoreKind { Byte, Half, Word }
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AluImmKind { Add, SetLessThan, SetLessThanUnsigned, Xor, Or, And }
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ShiftKind { LeftLogical, RightLogical, RightArithmetic }
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AluKind { Add, Sub, SetLessThan, SetLessThanUnsigned, Xor, Or, And, ShiftLeftLogical, ShiftRightLogical, ShiftRightArithmetic }
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MulDivKind { Mul, Mulh, Mulhsu, Mulhu, Div, Divu, Rem, Remu }
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Instruction { Lui { rd: u8, imm: i32 }, Auipc { rd: u8, imm: i32 }, Jal { rd: u8, imm: i32 }, Jalr { rd: u8, rs1: u8, imm: i32 }, Branch { kind: BranchKind, rs1: u8, rs2: u8, imm: i32 }, Load { kind: LoadKind, rd: u8, rs1: u8, imm: i32 }, Store { kind: StoreKind, rs1: u8, rs2: u8, imm: i32 }, OpImm { kind: AluImmKind, rd: u8, rs1: u8, imm: i32 }, ShiftImm { kind: ShiftKind, rd: u8, rs1: u8, shamt: u8 }, Op { kind: AluKind, rd: u8, rs1: u8, rs2: u8 }, MulDiv { kind: MulDivKind, rd: u8, rs1: u8, rs2: u8 }, Fence, FenceI, Ecall, Ebreak }
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct DecoderConfig { pub enable_mul_div: bool }
impl Default for DecoderConfig { fn default() -> Self { Self { enable_mul_div: true } } }
impl DecoderConfig { pub fn new() -> Self { Self::default() } }
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum DecodeError { CompressedInstruction(u16), UnsupportedOpcode(u8), UnsupportedInstruction { opcode: u8, funct3: u8, funct7: u8 }, DisabledExtension(&'static str) }
impl fmt::Display for DecodeError { fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result { match self { Self::CompressedInstruction(bits) => write!(f, "compressed instructions are not supported: 0x{bits:04x}"), Self::UnsupportedOpcode(opcode) => write!(f, "unsupported opcode: 0b{opcode:07b}"), Self::UnsupportedInstruction { opcode, funct3, funct7 } => write!(f, "unsupported instruction: opcode=0b{opcode:07b}, funct3=0b{funct3:03b}, funct7=0b{funct7:07b}"), Self::DisabledExtension(name) => write!(f, "disabled extension: {name}") } } }
impl std::error::Error for DecodeError {}
pub fn decode(word: u32, config: &DecoderConfig) -> Result<Instruction, DecodeError> { if word & 0b11 != 0b11 { return Err(DecodeError::CompressedInstruction((word & 0xffff) as u16)); } let opcode = bits(word, 0, 7) as u8; let rd = bits(word, 7, 5) as u8; let funct3 = bits(word, 12, 3) as u8; let rs1 = bits(word, 15, 5) as u8; let rs2 = bits(word, 20, 5) as u8; let funct7 = bits(word, 25, 7) as u8; match opcode { 0b0110111 => Ok(Instruction::Lui { rd, imm: u_imm(word) }), 0b0010111 => Ok(Instruction::Auipc { rd, imm: u_imm(word) }), 0b1101111 => Ok(Instruction::Jal { rd, imm: j_imm(word) }), 0b1100111 => match funct3 { 0b000 => Ok(Instruction::Jalr { rd, rs1, imm: i_imm(word) }), _ => Err(DecodeError::UnsupportedInstruction { opcode, funct3, funct7 }) }, 0b1100011 => { let kind = match funct3 { 0b000 => BranchKind::Beq, 0b001 => BranchKind::Bne, 0b100 => BranchKind::Blt, 0b101 => BranchKind::Bge, 0b110 => BranchKind::Bltu, 0b111 => BranchKind::Bgeu, _ => { return Err(DecodeError::UnsupportedInstruction { opcode, funct3, funct7 }); } }; Ok(Instruction::Branch { kind, rs1, rs2, imm: b_imm(word) }) } 0b0000011 => { let kind = match funct3 { 0b000 => LoadKind::Byte, 0b001 => LoadKind::Half, 0b010 => LoadKind::Word, 0b100 => LoadKind::ByteUnsigned, 0b101 => LoadKind::HalfUnsigned, _ => { return Err(DecodeError::UnsupportedInstruction { opcode, funct3, funct7 }); } }; Ok(Instruction::Load { kind, rd, rs1, imm: i_imm(word) }) } 0b0100011 => { let kind = match funct3 { 0b000 => StoreKind::Byte, 0b001 => StoreKind::Half, 0b010 => StoreKind::Word, _ => { return Err(DecodeError::UnsupportedInstruction { opcode, funct3, funct7 }); } }; Ok(Instruction::Store { kind, rs1, rs2, imm: s_imm(word) }) } 0b0010011 => match funct3 { 0b000 => Ok(Instruction::OpImm { kind: AluImmKind::Add, rd, rs1, imm: i_imm(word) }), 0b010 => Ok(Instruction::OpImm { kind: AluImmKind::SetLessThan, rd, rs1, imm: i_imm(word) }), 0b011 => Ok(Instruction::OpImm { kind: AluImmKind::SetLessThanUnsigned, rd, rs1, imm: i_imm(word) }), 0b100 => Ok(Instruction::OpImm { kind: AluImmKind::Xor, rd, rs1, imm: i_imm(word) }), 0b110 => Ok(Instruction::OpImm { kind: AluImmKind::Or, rd, rs1, imm: i_imm(word) }), 0b111 => Ok(Instruction::OpImm { kind: AluImmKind::And, rd, rs1, imm: i_imm(word) }), 0b001 if funct7 == 0b0000000 => Ok(Instruction::ShiftImm { kind: ShiftKind::LeftLogical, rd, rs1, shamt: rs2 }), 0b101 if funct7 == 0b0000000 => Ok(Instruction::ShiftImm { kind: ShiftKind::RightLogical, rd, rs1, shamt: rs2 }), 0b101 if funct7 == 0b0100000 => Ok(Instruction::ShiftImm { kind: ShiftKind::RightArithmetic, rd, rs1, shamt: rs2 }), _ => Err(DecodeError::UnsupportedInstruction { opcode, funct3, funct7 }) }, 0b0110011 => match (funct7, funct3) { (0b0000000, 0b000) => Ok(Instruction::Op { kind: AluKind::Add, rd, rs1, rs2 }), (0b0100000, 0b000) => Ok(Instruction::Op { kind: AluKind::Sub, rd, rs1, rs2 }), (0b0000000, 0b001) => Ok(Instruction::Op { kind: AluKind::ShiftLeftLogical, rd, rs1, rs2 }), (0b0000000, 0b010) => Ok(Instruction::Op { kind: AluKind::SetLessThan, rd, rs1, rs2 }), (0b0000000, 0b011) => Ok(Instruction::Op { kind: AluKind::SetLessThanUnsigned, rd, rs1, rs2 }), (0b0000000, 0b100) => Ok(Instruction::Op { kind: AluKind::Xor, rd, rs1, rs2 }), (0b0000000, 0b101) => Ok(Instruction::Op { kind: AluKind::ShiftRightLogical, rd, rs1, rs2 }), (0b0100000, 0b101) => Ok(Instruction::Op { kind: AluKind::ShiftRightArithmetic, rd, rs1, rs2 }), (0b0000000, 0b110) => Ok(Instruction::Op { kind: AluKind::Or, rd, rs1, rs2 }), (0b0000000, 0b111) => Ok(Instruction::Op { kind: AluKind::And, rd, rs1, rs2 }), (0b0000001, 0b000) => mul_div(config, MulDivKind::Mul, rd, rs1, rs2), (0b0000001, 0b001) => mul_div(config, MulDivKind::Mulh, rd, rs1, rs2), (0b0000001, 0b010) => mul_div(config, MulDivKind::Mulhsu, rd, rs1, rs2), (0b0000001, 0b011) => mul_div(config, MulDivKind::Mulhu, rd, rs1, rs2), (0b0000001, 0b100) => mul_div(config, MulDivKind::Div, rd, rs1, rs2), (0b0000001, 0b101) => mul_div(config, MulDivKind::Divu, rd, rs1, rs2), (0b0000001, 0b110) => mul_div(config, MulDivKind::Rem, rd, rs1, rs2), (0b0000001, 0b111) => mul_div(config, MulDivKind::Remu, rd, rs1, rs2), _ => Err(DecodeError::UnsupportedInstruction { opcode, funct3, funct7 }) }, 0b0001111 => match funct3 { 0b000 => Ok(Instruction::Fence), 0b001 => Ok(Instruction::FenceI), _ => Err(DecodeError::UnsupportedInstruction { opcode, funct3, funct7 }) }, 0b1110011 => match (funct3, bits(word, 20, 12)) { (0b000, 0) => Ok(Instruction::Ecall), (0b000, 1) => Ok(Instruction::Ebreak), _ => Err(DecodeError::UnsupportedInstruction { opcode, funct3, funct7 }) }, _ => Err(DecodeError::UnsupportedOpcode(opcode)) } }
fn mul_div(config: &DecoderConfig, kind: MulDivKind, rd: u8, rs1: u8, rs2: u8) -> Result<Instruction, DecodeError> { if config.enable_mul_div { Ok(Instruction::MulDiv { kind, rd, rs1, rs2 }) } else { Err(DecodeError::DisabledExtension("M")) } }
fn bits(word: u32, shift: u32, width: u32) -> u32 { (word >> shift) & ((1u32 << width) - 1) }
fn sign_extend(value: u32, width: u32) -> i32 { let shift = 32 - width; ((value << shift) as i32) >> shift }
fn i_imm(word: u32) -> i32 { sign_extend(bits(word, 20, 12), 12) }
fn s_imm(word: u32) -> i32 { let imm = (bits(word, 25, 7) << 5) | bits(word, 7, 5); sign_extend(imm, 12) }
fn b_imm(word: u32) -> i32 { let imm = (bits(word, 31, 1) << 12) | (bits(word, 7, 1) << 11) | (bits(word, 25, 6) << 5) | (bits(word, 8, 4) << 1); sign_extend(imm, 13) }
fn u_imm(word: u32) -> i32 { (word & 0xfffff000) as i32 }
fn j_imm(word: u32) -> i32 { let imm = (bits(word, 31, 1) << 20) | (bits(word, 12, 8) << 12) | (bits(word, 20, 1) << 11) | (bits(word, 21, 10) << 1); sign_extend(imm, 21) }